")\n}\n\n/// ClockIn (Pointage) - Time tracking event\nmodel ClockIn {\n  id         String        @id @default(cuid())\n  tenantId   String\n  siteId     String\n  employeeId String\n  action     ClockInAction\n  timestamp  DateTime      @default(now())\n  createdAt  DateTime      @default(now())\n\n  // Relations\n  tenant    Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  site      Site      @relation(fields: [siteId], references: [id], onDelete: Cascade)\n  employee  Employee  @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  anomalies Anomaly[]\n\n  @@index([tenantId, siteId, employeeId, timestamp])\n  @@map(\"clock_ins\")\n}\n\n/// QrToken (Token QR) - Single-use token for secure clock-in\nmodel QrToken {\n  id        String    @id @default(cuid())\n  tenantId  String\n  siteId    String\n  token     String    @unique\n  used      Boolean   @default(false)\n  usedAt    DateTime?\n  expiresAt DateTime\n  createdAt DateTime  @default(now())\n\n  // Relations\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  site   Site   @relation(fields: [siteId], references: [id], onDelete: Cascade)\n\n  @@index([token, used, expiresAt])\n  @@map(\"qr_tokens\")\n}\n\n/// Anomaly (Anomalie) - Detected suspicious pattern\nmodel Anomaly {\n  id               String        @id @default(cuid())\n  tenantId         String\n  type             AnomalyType\n  description      String\n  status           AnomalyStatus @default(PENDING)\n  relatedClockInId String?\n  createdAt        DateTime      @default(now())\n  resolvedAt       DateTime?\n\n  // Relations\n  tenant         Tenant   @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  relatedClockIn ClockIn? @relation(fields: [relatedClockInId], references: [id], onDelete: SetNull)\n\n  @@index([tenantId, status])\n  @@map(\"anomalies\")\n}\n\n// ============================================\n// NEXTAUTH MODELS\n// ============================================\n\n/// User (NextAuth) - Authentication user\nmodel User {\n  id            String    @id @default(cuid())\n  name          String?\n  email         String    @unique\n  emailVerified DateTime?\n  image         String?\n  tenantId      String?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  // Relations\n  tenant   Tenant?   @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  accounts Account[]\n  sessions Session[]\n\n  @@map(\"users\")\n}\n\n/// Account (NextAuth) - OAuth accounts\nmodel Account {\n  userId            String\n  type              String\n  provider          String\n  providerAccountId String\n  refresh_token     String?\n  access_token      String?\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String?\n  session_state     String?\n  createdAt         DateTime @default(now())\n  updatedAt         DateTime @updatedAt\n\n  // Relations\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@id([provider, providerAccountId])\n  @@map(\"accounts\")\n}\n\n/// Session (NextAuth) - User sessions\nmodel Session {\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  // Relations\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"sessions\")\n}\n\n/// VerificationToken (NextAuth) - Email verification tokens\nmodel VerificationToken {\n  identifier String\n  token      String\n  expires    DateTime\n\n  @@id([identifier, token])\n  @@map(\"verification_tokens\")\n}\n\n// ============================================\n// ENUMS\n// ============================================\n\nenum ClockInAction {\n  START\n  PAUSE\n  END\n}\n\nenum AnomalyType {\n  DUPLICATE_CLOCK_IN // 2 pointages même employé en < 5 min\n  IMPOSSIBLE_HOURS // Pointage à des heures impossibles (ex: 3h du matin)\n  MISSING_END // Début sans fin de journée\n  EXCESSIVE_HOURS // Plus de 12h de travail sans pause\n  SUSPICIOUS_PATTERN // Pattern suspect détecté\n}\n\nenum AnomalyStatus {\n  PENDING\n  REVIEWED\n  RESOLVED\n}\n",
